const PROTECTED_PATHS = [
  "src/core/",
  "src/llm/",
  "src/memory/",
  "src/primitives/",
  "src/cli.ts",
  "src/ui/",
  "Dockerfile",
  "docker-compose.yml",
  "package.json",
  "pnpm-lock.yaml",
  "tsconfig.json",
];

function isProtectedPath(filePath: string): boolean {
  const abs = resolve(filePath);
  const rel = abs.replace(resolve(".") + "/", "");
  return PROTECTED_PATHS.some(p => rel.startsWith(p) || abs.includes(`/${p}`));
}

