import type { Tool } from "../../core/tools.js";
import { readFile } from "fs/promises";

const TARGET_FILES = [
  "src/extensions/tools/README.md",
  "src/extensions/tools/continuity_snapshot.ts",
  "src/extensions/tools/cycle_focus.ts",
  "src/extensions/tools/import_consistency_check.ts",
  "src/extensions/tools/llm_debug_probe.ts",
  "src/extensions/tools/self-check-summary.ts",
  "src/extensions/tools/wake_summary.ts",
];

function extractImportLines(source: string): string[] {
  return source
    .split(/\r?\n/)
    .filter((line) => line.trimStart().startsWith("import "));
}

function getModuleName(line: string): string | null {
  const match = line.match(/from\s+["']([^"']+)["']/);
  return match ? match[1] : null;
}

function isForbiddenModule(mod: string, file: string): boolean {
  const isCoreOrMemory = mod.startsWith("../../core/") || mod.startsWith("../../memory/");
  return isCoreOrMemory && file !== "src/extensions/tools/README.md";
}

function isAllowedTopLevelModule(mod: string): boolean {
  return mod === "../../core/tools.js" || mod === "fs/promises" || mod === "path";
}

export const tool: Tool = {
  def: {
    name: "import_consistency_check",
    description: "README와 확장 도구 구현의 import 관례가 서로 맞는지 빠르게 점검한다.",
    input_schema: {
      type: "object",
      properties: {},
      additionalProperties: false,
    },
  },
  handler: async () => {
    const results: string[] = [];
    let violations = 0;

    for (const file of TARGET_FILES) {
      try {
        const text = await readFile(file, "utf-8");
        const imports = extractImportLines(text);
        results.push(`## ${file}`);
        if (imports.length === 0) {
          results.push("(import 없음)");
        } else {
          results.push(imports.join("\n"));
          for (const line of imports) {
            const mod = getModuleName(line);
            if (!mod) continue;
            if (!isAllowedTopLevelModule(mod) && isForbiddenModule(mod, file)) {
              violations += 1;
              results.push(`[위반] ${line}`);
            }
          }
        }
      } catch (error) {
        results.push(`## ${file}`);
        results.push(`[읽기 실패] ${String(error)}`);
      }
      results.push("");
    }

    const summary = violations === 0
      ? "판정: 통과"
      : `판정: 실패 (${violations}개 위반)`;
    results.push(summary);
    results.push(`위반 수: ${violations}`);
    return results.join("\n").trim();
  },
};
